import hashlib
from datetime import date

class User:
    def __init__(self, id, name, tier):
        self.id = id
        self.name = name
        self.tier = tier

class DiscountCode:
    def __init__(self, code, description, admin_only=False, user_tiers=None):
        self.code = code
        self.description = description
        self.admin_only = admin_only
        self.user_tiers = user_tiers if user_tiers else []

class CartItem:
    def __init__(self, id, name, price, quantity):
        self.id = id
        self.name = name
        self.price = price
        self.quantity = quantity

class Order:
    def __init__(self, cart_items, discount_code=None, tax_rate=0.08):
        self.cart_items = cart_items
        self.discount_code = discount_code
        self.tax_rate = tax_rate
        self.total = 0

def validate_cart_items(cart_items):
    for item in cart_items:
        if item.quantity < 1:
            return False
    return True

def apply_discount_code(order, discount_code):
    if not order.user.has_permission(discount_code.admin_only) or (discount_code.user_tiers and discount_code.user_tiers != order.user.tier):
        raise ValueError("Invalid discount code")
    order.total *= (1 - discount_code.discount / 100)

def calculate_tax(order):
    order.tax = order.total * order.tax_rate

def process_payment(order, payment_method):
    # Simulate payment processing
    print(f"Payment processed using {payment_method}")

def create_order_record(order):
    # Simulate database insertion
    print(f"Order record created for user {order.user.name} on {date.today()}")

class Checkout:
    def __init__(self, cart_items, user):
        self.cart_items = [CartItem(**item) for item in cart_items]
        self.user = User(**user)

    def checkout(self, discount_code=None):
        if not validate_cart_items(self.cart_items):
            raise ValueError("Invalid cart items")
        
        order = Order(self.cart_items, discount_code)
        apply_discount_code(order, discount_code)
        calculate_tax(order)
        process_payment(order, "Credit Card")
        create_order_record(order)

